-- 📌 성경 사전(Bible Dictionary) 샘플 데이터 삽입
INSERT INTO dictionary (id, term, description, related_verses, created_at, updated_at)
VALUES (1, '은혜', '값 없이 베풀어지는 호의나 선물로, 하나님이 주시는 호의와 은사를 가리킨다.', '에베소서 2:8-9, 요한복음 1:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (2, '믿음', '하나님과 그 말씀을 신뢰하고 의지하는 태도를 뜻하며, 보이지 않는 것을 확신하는 믿음을 가리킨다.', '히브리서 11:1, 로마서 10:17', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (3, '의', '옳고 바른 상태나 행위를 뜻하며, 하나님의 기준에 맞는 상태를 가리킨다.', '로마서 1:17, 신명기 6:25', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (4, '칭의', '의롭다고 인정하거나 선언하는 일을 뜻하며, 하나님이 의롭다 하시는 선언을 가리킨다.', '로마서 5:1, 갈라디아서 2:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (5, '성화', '거룩하게 구별됨과 거룩함에 이르는 것을 뜻하며, 거룩함을 이루어 가는 상태를 가리킨다.', '데살로니가전서 4:3, 히브리서 12:14', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (6, '영화', '영광스럽게 됨을 뜻하며, 영광 가운데 세워지거나 변화되는 상태를 가리킨다.', '로마서 8:30, 빌립보서 3:21', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (7, '회개', '자신의 죄를 깨닫고 마음을 바꾸어 죄에서 떠나 하나님께로 돌아가는 것을 뜻하며, 하나님이 이 돌아옴을 받아들이시고 그 결과로 삶이 달라지는 것을 가리킨다.', '사도행전 20:21, 사도행전 26:20, 이사야 55:7, 누가복음 15:7, 누가복음 15:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (8, '구원', '위험이나 멸망에서 건져내는 일을 뜻하며, 죄와 죽음에서의 건짐을 가리킨다.', '로마서 6:23, 시편 62:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (9, '언약', '당사자 사이에 맺는 약속이나 조약을 뜻하며, 하나님과 사람이 맺는 약속 관계를 가리킨다.', '창세기 9:9, 예레미야 31:33', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (10, '율법', '하나님이 백성에게 주신 가르침과 명령을 뜻하며, 계명과 규례를 포함한 삶의 기준으로 사용된다. 성경에서 율법은 하나님의 뜻을 밝히 드러내어 죄를 깨닫게 하고, 사람을 그리스도께로 이끄는 역할을 한다.', '출애굽기 20:1-17, 시편 19:7, 로마서 7:7, 갈라디아서 3:24', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (11, '복음', '기쁜 소식을 뜻하는 말로, 예수 그리스도의 죽음과 부활을 통해 하나님이 이루신 구원의 소식을 가리킨다. 이는 사람에게 믿음을 요구하며 구원을 가져오는 소식으로 선포된다.', '로마서 1:16, 고린도전서 15:3-4, 마가복음 1:14-15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (12, '그리스도', '기름 부음을 받은 자를 뜻하는 칭호로, 구약에서는 하나님이 세우신 왕이나 지도자를 가리키는 말로 사용되며, 신약에서는 예수가 그 약속된 그리스도로 선포된다. 성경에서 그리스도는 하나님의 뜻을 이루기 위해 세움 받은 자를 의미한다.', '마태복음 16:16, 시편 2:2, 사도행전 2:36', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (13, '메시아', '기름 부음을 받은 자를 뜻하는 히브리어 표현으로, 구약에서는 하나님이 보내실 왕적 인물을 가리키는 말로 사용되며, 유대 전통에서는 하나님의 뜻을 이루기 위해 오실 구원자를 가리켜 기대된 호칭이다. 신약에서는 이 메시아가 예수와 동일시된다.', '이사야 9:6, 다니엘 9:25, 요한복음 1:41', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (14, '속죄', '죄로 인해 생긴 문제를 제거하거나 가려 관계를 회복하는 행위를 뜻하며, 제사와 피의 사용을 통해 죄가 처리되는 과정을 가리킬 때 사용된다.', '레위기 17:11, 레위기 16:30, 히브리서 9:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (15, '대속', '다른 이를 대신하여 값을 지불하거나 책임을 감당하는 행위를 뜻하며, 죄나 형벌의 문제를 대신 짊어지는 경우를 가리킬 때 사용된다.', '마가복음 10:45, 이사야 53:5, 이사야 53:12', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (16, '부활', '죽은 자가 다시 살아나는 것을 뜻하며, 죽음 이후에 몸을 가진 상태로 생명이 회복되는 사건을 가리킬 때 사용된다.', '고린도전서 15:20, 요한복음 11:25, 사도행전 24:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (17, '재림', '다시 오는 것을 뜻하는 말로, 예수 그리스도가 떠난 후 다시 오심을 가리킬 때 사용된다.', '마태복음 24:30, 사도행전 1:11, 데살로니가전서 4:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (18, '천국', '하늘의 나라를 뜻하는 표현으로, 하나님이 왕으로 다스리시는 영역과 통치를 가리킨다. 복음서에서는 하나님의 다스림이 선포되고 드러나는 현실을 가리켜 사용되며, 장차 완전히 이루어질 하나님의 나라를 포함해 말한다.', '마태복음 4:17, 마태복음 6:10, 요한계시록 21:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (19, '지옥', '성경에서 하나님께 심판받는 최종 상태를 가리키는 표현으로, 불, 어둠, 멸망과 같은 이미지로 묘사되며 하나님으로부터의 단절과 형벌이 지속되는 곳으로 설명된다.', '마태복음 25:46, 마가복음 9:43, 요한계시록 20:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (20, '심판', '하나님이 사람의 행위와 삶을 기준으로 판단하고 그에 따른 결과를 정하시는 일을 가리키는 말로, 모든 사람이 하나님 앞에 서서 판결을 받는 사건으로 묘사된다.', '히브리서 9:27, 고린도후서 5:10, 전도서 12:14', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (21, '성령', '하나님의 영, 그리스도의 영, 거룩한 영으로 불리며 하나님께서 보내셔서 사람 가운데 임재하신다. 성령은 하나님을 알게 하고 진리로 인도하며, 죄와 의와 심판에 대해 깨닫게 하고 책망하며 능력을 주시는 분으로 묘사된다.', '요한복음 14:26, 요한복음 16:8, 로마서 8:9, 고린도전서 2:10-12, 사도행전 1:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (22, '삼위일체', '성경에 직접 기록된 용어는 아니며, 성부·성자·성령을 함께 언급하는 성경의 표현을 설명하기 위해 사용되는 신학 용어이다. 이 용어는 하나님이 성부와 성자와 성령으로 나타나 역사하심을 성경 전체의 증언에 따라 정리한 개념을 가리킨다.', '마태복음 28:19, 고린도후서 13:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (23, '예배', '하나님을 존귀하게 여기고 그분께 경배와 순종을 드리는 것을 뜻하며, 정해진 의식뿐 아니라 삶 전체로 하나님을 섬기는 것을 가리킨다.', '요한복음 4:24, 로마서 12:1, 시편 95:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (24, '기도', '하나님께 마음을 열어 말하는 것을 뜻하며, 간구와 감사, 찬양과 고백을 통해 하나님의 뜻을 구하고 도움을 구하는 행위를 가리킨다.', '빌립보서 4:6, 마태복음 6:9-13, 시편 62:8', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (25, '찬양', '하나님의 성품과 행하신 일을 인정하고 높이는 것을 뜻하며, 말과 행동으로 하나님께 감사를 표현하는 것을 가리킨다.', '시편 150:1-6, 히브리서 13:15, 시편 103:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (26, '감사', '하나님께서 베푸신 은혜와 행하신 일을 기억하고 고백하는 것을 뜻하며, 모든 상황 속에서 하나님께 고마움을 표현하는 행위를 가리킨다.', '데살로니가전서 5:18, 시편 107:1, 시편 136:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (27, '교회', '부름받은 사람들의 모임을 뜻하는 말로, 예수 그리스도를 믿는 사람들이 모여 하나님을 섬기고 서로 교제하는 공동체를 가리킨다.', '마태복음 16:18, 에베소서 1:23, 사도행전 2:42', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (28, '제자', '예수 그리스도를 따르며 그의 가르침을 배우고 삶으로 실천하는 사람을 가리킨다.', '누가복음 9:23, 마태복음 28:19-20', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (29, '사도', '보냄을 받은 자를 뜻하는 말로, 예수 그리스도에 의해 세워져 복음을 전하고 그분의 일을 증언하도록 파송된 사람을 가리킨다.', '마태복음 10:1-2, 사도행전 1:21-22, 에베소서 2:20', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (30, '선교', '보냄을 받은 사람들이 하나님의 말씀과 복음을 전하기 위해 다른 지역과 민족에게 나아가는 일을 뜻하며, 하나님께서 사람을 보내셔서 그 뜻을 전하게 하시는 사역을 가리킨다.', '마태복음 24:14, 마태복음 28:19, 사도행전 13:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (31, '사랑', '하나님이 먼저 인간을 사랑하셨으며 그 사랑이 예수 그리스도를 통해 나타났다고 말한다. 또한 이 사랑을 받은 사람들은 말이나 감정에 머무르지 않고 하나님 사랑과 이웃 사랑을 행동으로 실천해야 하는 태도로 설명된다.', '요한일서 4:8, 요한일서 4:10-11, 요한복음 3:16, 고린도전서 13:4-7, 요한일서 3:18', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (32, '소망', '막연한 기대가 아니라 하나님이 약속하신 것을 신뢰하며 바라보는 확신을 뜻하며, 예수 그리스도의 부활로 말미암아 주어진 미래에 대한 기대를 가리킨다.', '로마서 15:13, 베드로전서 1:3, 히브리서 6:19', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (33, '겸손', '자신을 낮추어 하나님을 의지하고 다른 사람을 자기보다 높게 여기는 태도를 뜻하며, 하나님의 뜻 앞에서 자신을 낮추는 삶의 자세를 가리킨다.', '빌립보서 2:3, 미가 6:8, 야고보서 4:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (34, '순종', '하나님의 말씀과 뜻에 따르는 것을 뜻하며, 하나님의 명령에 귀를 기울여 행하는 태도를 가리킨다. 율법에서는 하나님의 말씀에 대한 순종을 강조하며, 복음에서는 하나님을 사랑함으로 자발적으로 따르는 삶의 자세로 묘사된다.', '사무엘상 15:22, 요한복음 14:15, 로마서 6:17', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (35, '거룩', '구별됨을 뜻하는 말로, 하나님께서 자신에게 속하도록 구별하신 상태를 가리킨다. 하나님은 거룩하신 분이며, 그분이 구별하신 사람과 삶도 하나님의 뜻에 따라 거룩하게 살도록 부름받는다.', '레위기 19:2, 레위기 20:8, 출애굽기 19:6, 출애굽기 31:13, 에스겔 37:28, 베드로전서 1:16, 고린도전서 1:2, 히브리서 10:10', CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP),
       (36, '성결', '하나님께서 인간의 죄를 깨끗하게 하셔서 정결하게 하신 상태를 가리키며, 그 결과로 죄에서 떠나 하나님 뜻에 합당하게 살아가도록 나타나는 삶의 모습을 뜻한다.', '히브리서 12:14, 시편 51:10, 데살로니가전서 4:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (37, '섬김', '예수 그리스도가 섬김을 받으려 하지 않고 오히려 섬기며 자신을 내어주신 일을 먼저 보여 준다. 이 섬김을 본으로 삼아, 다른 사람의 유익을 위해 자신을 낮추고 사랑으로 행하는 삶의 태도를 가리킨다.', '마가복음 10:45, 요한복음 13:14-15, 갈라디아서 5:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (38, '안식', '하나님이 창조를 마치고 쉬신 것에 근거한 개념으로, 하나님께서 정하신 때에 일을 멈추고 하나님을 기억하며 누리는 쉼을 뜻한다. 또한 하나님의 약속 안에서 누리는 참된 쉼을 가리킬 때 사용된다.', '출애굽기 20:8, 창세기 2:2-3, 히브리서 4:9-10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (39, '시험', '사람의 믿음과 순종이 드러나도록 허락된 상황을 가리키며, 이를 통해 믿음이 연단되고 인내가 이루어지는 과정을 뜻한다.', '야고보서 1:2-3, 창세기 22:1, 베드로전서 1:6-7', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (40, '유혹', '사람이 자기 욕심에 끌려 죄를 선택하도록 부추기는 작용을 가리키며, 죄로 이어질 위험을 지닌 내적·외적 자극을 뜻한다.', '야고보서 1:14-15, 창세기 3:1-6, 마태복음 4:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (41, '죄', '하나님의 뜻과 기준에서 벗어난 생각과 말과 행위를 가리키며, 이로 인해 하나님과의 관계가 깨어지고 단절되는 상태를 뜻한다.', '로마서 3:23, 이사야 59:2, 요한일서 3:4', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (42, '타락', '죄로 인해 인간이 하나님과의 바른 관계에서 벗어나 죄와 죽음의 영향 아래 놓이게 된 상태와 그 결과를 가리킨다.', '창세기 3:6-7, 로마서 5:12, 전도서 7:29', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (43, '속량', '값을 치르고 풀어주는 것을 뜻하는 말로, 하나님이 예수 그리스도를 통해 죄와 율법의 속박 아래 있던 사람들을 대가를 지불하여 자유롭게 하신 일을 가리킨다.', '에베소서 1:7, 갈라디아서 4:5, 마가복음 10:45', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (44, '화목', '죄로 인해 하나님과 원수가 된 관계가 하나님께서 행하신 일로 회복되어 평화를 이루게 되는 것을 뜻하며, 예수 그리스도를 통해 하나님과 다시 올바른 관계에 이르게 되는 상태를 가리킨다.', '로마서 5:10, 고린도후서 5:18-19, 에베소서 2:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (45, '양자', '하나님께서 예수 그리스도를 통해 믿는 사람들을 자신의 자녀로 받아들이시는 일을 가리키며, 그 결과 하나님을 아버지라 부르고 자녀의 신분과 권리를 누리게 되는 것을 뜻한다.', '로마서 8:15, 갈라디아서 4:5, 에베소서 1:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (46, '영생', '단순히 끝이 없는 생명이 아니라, 하나님과의 관계 안에서 누리는 참된 생명을 뜻하며, 예수 그리스도를 통해 하나님을 아는 것으로 주어지는 생명을 가리킨다.', '요한복음 17:3, 요한일서 5:11, 요한복음 3:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (47, '말씀', '하나님께서 자신의 뜻을 나타내시고 알리시는 표현을 가리키며, 하나님의 계시와 명령, 약속을 포함해 사용된다. 신약에서는 예수 그리스도가 곧 하나님의 말씀이며, 이 말씀은 살아 있어 사람의 마음과 삶을 판단하고 변화시키는 능력으로 묘사된다.', '요한복음 1:1, 요한복음 1:14, 히브리서 4:12, 시편 119:105', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (48, '계시', '하나님께서 자신과 그 뜻을 사람에게 알리시는 일을 가리킨다. 하나님은 창조 세계와 말씀을 통해 자신을 드러내셨고, 예수 그리스도를 통해 가장 분명하게 나타내셨다.', '히브리서 1:1-2, 로마서 1:20, 요한복음 1:18', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (49, '지혜', '하나님의 지혜가 예수 그리스도로 나타났다고 말하며, 이 지혜를 받은 사람은 하나님을 경외하고, 삶의 현실 속에서 하나님의 뜻을 분별하고 바르게 행하게 된다.', '고린도전서 1:24, 잠언 1:7, 잠언 9:10, 전도서 12:13, 야고보서 1:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (50, '지식', '단순한 정보나 이해를 넘어 하나님을 알고 그분의 뜻을 인식하는 것을 가리키며, 이러한 지식은 하나님과의 관계 속에서 자라고 삶의 열매로 나타나는 깨달음을 뜻한다.', '호세아 6:6, 골로새서 1:10, 예레미야 9:24', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (51, '종말', '하나님의 구원 역사와 심판의 과정이 완성되는 마지막 때를 가리키며, 예수 그리스도의 다시 오심과 하나님의 나라가 완전히 드러나는 시점을 포함해 말한다.', '마태복음 24:14, 마태복음 24:30, 요한계시록 22:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (52, '새 하늘과 새 땅', '하나님께서 이전의 하늘과 땅을 지나가게 하시고 새롭게 창조하실 세계를 가리키며, 죄와 죽음이 사라지고 하나님이 사람들과 함께 거하시는 완성된 상태를 뜻한다.', '이사야 65:17, 요한계시록 21:1, 요한계시록 21:3-4', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (53, '왕국', '왕이 다스리는 영역을 뜻하되, 특히 하나님이 왕으로서 다스리시는 통치와 주권을 가리킨다. 하나님의 왕국은 하나님의 뜻과 권세가 이루어지는 통치의 영역과 상태를 포함해 사용된다.', '마태복음 6:33, 시편 103:19, 다니엘 4:34', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (54, '하나님 나라', '하나님이 왕으로 다스리시는 통치를 가리키는 표현으로, 예수 그리스도를 통해 선포되고 나타나며 지금 임해 있으면서도 장차 완전히 이루어질 나라를 뜻한다.', '누가복음 17:21, 마태복음 13:31, 마가복음 1:15', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (55, '중보', '하나님과 사람 사이에 서서 관계를 이어 주는 일을 가리키며, 특히 예수 그리스도가 하나님과 사람 사이의 유일한 중보자로서 사람을 대신해 하나님께 나아가시는 역할을 뜻한다.', '디모데전서 2:5, 히브리서 7:25, 로마서 8:34', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (56, '제사', '하나님께서 정하신 방식에 따라 제물을 드려 죄의 문제를 다루고 하나님과의 관계를 유지하거나 회복하려는 행위를 가리킨다. 이는 구약에서 반복적으로 행해졌으며, 신약에서는 예수 그리스도의 단번의 희생으로 완성된 것으로 설명된다.', '레위기 1:4, 레위기 17:11, 히브리서 10:10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (57, '희생', '하나님을 위해 자신을 내어주는 행위를 가리키며, 예수 그리스도가 사람을 위해 자신의 생명을 내어주신 일을 통해 그 의미가 분명히 드러난다. 또한 믿는 사람의 삶에서도 하나님께 자신을 드리는 헌신의 모습으로 나타난다.', '요한복음 15:13, 로마서 12:1, 에베소서 5:2', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (58, '순교', '신앙이나 신념으로 인해 죽음을 맞는 일을 의미하며, 믿음으로 인해 죽임을 당한 일을 가리킨다.', '요한계시록 2:10, 사도행전 7:59', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (59, '충성', '하나님과의 언약에 끝까지 성실히 머무는 태도를 가리킨다. 이 충성은 하나님의 아들 예수 그리스도가 아버지 하나님께 끝까지 순종하고 신실하게 충성하신 모습에서 완전히 드러났으며, 이를 본받아 하나님께서 맡기신 일과 관계에 신실하게 응답하는 삶의 태도를 뜻한다.', '신명기 7:9, 시편 89:8, 히브리서 3:2, 요한복음 6:38, 마태복음 25:21, 고린도전서 4:2', CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP),
       (60, '영광', '하나님의 존재와 행하심에서 드러나는 무게와 위엄을 가리키며, 하나님의 거룩함과 능력, 존귀함이 나타나는 것을 뜻한다. 모든 영광은 하나님께 속하며 하나님께로 돌아가야 할 것으로 묘사된다.', '이사야 6:3, 로마서 11:36, 시편 24:7-10', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (61, '창조', '하나님께서 자신의 말씀으로 만물을 존재하게 하신 일을 가리키며, 보이는 것과 보이지 않는 모든 것이 하나님의 뜻과 능력으로 시작되었음을 뜻한다.', '창세기 1:1, 히브리서 11:3, 시편 33:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (62, '섭리', '하나님께서 창조하신 세계와 모든 일을 보존하시고 다스리며, 자신의 뜻에 따라 이루어 가시는 일을 가리킨다. 이는 우연처럼 보이는 일들까지도 하나님의 뜻과 계획 안에서 이루어짐을 포함해 말한다.', '마태복음 10:29, 로마서 8:28, 시편 103:19', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (63, '주권', '하나님이 만물과 역사 위에 절대적인 권세를 가지시고 자신의 뜻대로 행하시는 권위를 가리킨다. 이는 하늘과 땅의 모든 일이 하나님의 뜻과 허락 아래 이루어짐을 뜻한다.', '시편 115:3, 다니엘 4:35, 시편 103:19', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (64, '공의', '하나님께서 옳고 바르신 기준에 따라 판단하고 행하시는 성품과 행위를 가리키며, 하나님의 통치와 심판이 공정하고 올바름 위에 세워져 있음을 뜻한다.', '시편 89:14, 로마서 2:6, 신명기 32:4', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (65, '자비', '하나님께서 연약하고 죄 있는 사람을 불쌍히 여기시고 긍휼히 대하시는 성품과 행위를 가리킨다. 하나님의 자비는 용서와 인내로 나타나며, 이를 받은 사람들도 같은 자비를 베풀도록 부름받는다.', '시편 103:8, 누가복음 6:36, 미가 7:18', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (66, '긍휼', '하나님께서 고통과 연약함 가운데 있는 사람을 깊이 불쌍히 여기시고 실제로 도우시는 마음과 행위를 가리킨다. 이 긍휼은 하나님의 변함없는 사랑에서 나오며, 예수 그리스도의 사역 속에서 분명히 나타난다.', '마태복음 9:36, 애가 3:22-23, 시편 103:13', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (67, '인내', '고난과 시련 속에서도 믿음을 붙들고 끝까지 견디는 태도를 가리키며, 이를 통해 성숙과 소망이 이루어지는 과정을 뜻한다.', '야고보서 5:11, 로마서 5:3-4, 히브리서 12:11', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (68, '온유', '하나님을 신뢰함으로 힘을 절제하여 부드럽게 행하는 태도를 가리키며, 자기 권리를 내세우기보다 하나님의 뜻에 맡기고 다른 사람을 배려하는 삶의 자세를 뜻한다.', '마태복음 5:5, 갈라디아서 5:23, 민수기 12:3', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (69, '절제', '자신의 욕망과 행동을 스스로 다스리는 것을 뜻하며, 성령의 인도하심 아래 하나님 뜻에 맞게 삶을 조절하고 절제하는 태도를 가리킨다.', '고린도전서 9:25, 갈라디아서 5:23, 잠언 25:28', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (70, '의인', '하나님 앞에 의로운 자는 한 사람도 없으며, 오직 예수 그리스도만 죄 없으신 의로우신 분으로 증언된다. 또한 하나님은 예수 그리스도를 믿는 사람을 그분의 의로 인해 의롭다 여김받은 자로 부르신다.', '로마서 3:10, 요한일서 2:1, 로마서 4:5, 고린도후서 5:21', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (71, '악인', '하나님을 믿지 않고 그분의 뜻과 길에서 벗어나 자기 욕망과 판단을 따라 사는 사람을 가리키며, 이러한 삶의 결과로 하나님 앞에서 의롭지 않은 상태에 있는 이를 뜻한다.', '시편 1:1, 시편 1:6, 잠언 11:5, 이사야 53:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (72, '거짓 선지자', '거짓된 메시지를 전하는 사람을 의미하며, 하나님의 말씀을 왜곡하여 전하는 이를 가리킨다.', '마태복음 7:15, 베드로후서 2:1', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (73, '우상', '신처럼 섬겨지는 대상을 뜻하는 말로, 하나님 대신 숭배의 대상이 되는 것을 가리킨다.', '출애굽기 20:3-4, 이사야 44:9', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (74, '우상숭배', '우상을 섬기는 행위를 의미하며, 하나님 외의 대상을 숭배하는 행위를 가리킨다.', '로마서 1:23, 고린도전서 10:14', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (75, '거듭남', '다시 태어남을 의미하는 표현으로, 사람의 상태가 새롭게 되는 것을 가리킨다.', '요한복음 3:3, 디도서 3:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (76, '중생', '다시 살아남을 뜻하는 말로, 거듭남과 같은 의미로 사용된다.', '베드로전서 1:23, 에베소서 2:5', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (77, '확신', '의심 없이 믿는 상태를 뜻하며, 믿음과 관련된 분명한 인식을 가리킨다.', '요한일서 5:13, 히브리서 10:22', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (78, '순례자', '길을 따라 이동하는 사람을 뜻하는 말로, 이 땅을 지나가는 존재로서의 인간을 비유적으로 표현할 때 사용된다.', '히브리서 11:13, 베드로전서 2:11', CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP),
       (79, '제사장', '하나님께 구별되어 백성을 대신해 하나님께 나아가 제사를 드리고 하나님의 뜻을 전하는 역할을 맡은 사람을 가리킨다. 구약에서는 레위 계통이 이 직분을 맡았으며, 신약에서는 예수 그리스도가 대제사장으로 완성하시고 그를 믿는 이들이 제사장적 부르심에 참여한다고 말한다.', '출애굽기 19:6, 히브리서 4:14, 베드로전서 2:9', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
       (80, '왕 같은 제사장', '하나님께서 예수 그리스도를 통해 구속하신 백성에게 주신 정체성을 가리키는 표현으로, 하나님의 통치 아래에서 그분을 섬기며 세상 가운데 하나님의 뜻과 영광을 나타내도록 부름받은 공동체를 뜻한다.', '베드로전서 2:9, 요한계시록 1:6, 출애굽기 19:6', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),

       (81, '부르심', '어떤 대상으로 초대하거나 요청하는 행위를 뜻하는 말로, 하나님이 사람을 특정 목적이나 관계로 이끄시는 것을 가리킨다.', '로마서 8:30, 데살로니가전서 2:12', CURRENT_TIMESTAMP,
        CURRENT_TIMESTAMP),
       (82, '선택', '여러 대상 가운데 하나를 고르는 행위를 의미하며, 하나님이 특정 대상을 택하시는 것을 가리켜 사용된다.', '에베소서 1:4, 로마서 9:16', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
